mapper.select:
/* adm-master-owneradmincode-sql-oracle.xml - selectTOrderMstOrdCdHd */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK, A.OWKEY, O.OWNM, A.OWCDHDKEY, A.OWCDHDNM, A.DELYN, A.INSERTDATE, A.INSERTURKEY, A.UPDATEDATE, A.UPDATEURKEY FROM TADMIN_MST_OWCD_HD A JOIN TADMIN_MST_OW O ON A.OWKEY = O.OWKEY
#{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY A.UPDATEDATE DESC , LPAD(A.OWCDHDKEY::TEXT, 20, '0') ASC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		/* adm-master-owneradmincode-sql-oracle.xml - selectTOrderMstOrdCdHdCount */
        SELECT count(1)
          FROM TADMIN_MST_OWCD_HD A
          JOIN TADMIN_MST_OW O
		    ON A.OWKEY = O.OWKEY


			 	   #{SEARCH_CONDITION}

/* adm-master-owneradmincode-sql-oracle.xml - selectTOrderMstOrdCdDt */ SELECT '0' AS CHK , TB1.OWKEY , TB1.OWCDHDKEY , TB2.OWCDDTKEY , TB2.OWCDDTNM , TB2.OWCDDTVALUE , TB2.OWCDDTORDER , TB2.DELYN , TB2.CMT , TB2.LAKEY , TB2.INSERTDATE , TB2.INSERTURKEY , TB2.UPDATEDATE , TB2.UPDATEURKEY FROM TADMIN_MST_OWCD_HD TB1 JOIN TADMIN_MST_OWCD_DT TB2 ON TB1.OWKEY = TB2.OWKEY AND TB1.OWCDHDKEY = TB2.OWCDHDKEY AND TB1.OWKEY = #{owkey} AND TB1.OWCDHDKEY = #{owcdhdkey}
AND TB2.DELYN = #{delyn}
ORDER BY CASE WHEN TB2.LAKEY = 'KOR' THEN '0' ELSE '1' END, TB2.LAKEY, TB2.OWCDDTORDER ASC

/* adm-master-owneradmincode-sql-oracle.xml - selectTOrderMstOrdCdDTCount */ SELECT COUNT(1) FROM ( SELECT TB1.OWCDHDKEY ,TB2.OWCDDTKEY ,TB2.OWCDDTNM ,TB2.OWCDDTVALUE ,TB2.OWCDDTORDER ,TB2.CMT ,TB2.LAKEY ,TB2.INSERTDATE ,TB2.INSERTURKEY ,TB2.UPDATEDATE ,TB2.UPDATEURKEY FROM TADMIN_MST_OWCD_HD TB1 JOIN TADMIN_MST_OWCD_DT TB2 ON TB1.OWKEY = TB2.OWKEY AND TB1.OWCDHDKEY = TB2.OWCDHDKEY AND TB1.OWKEY = #{owkey} AND TB1.OWCDHDKEY = #{owcdhdkey}
AND TB2.DELYN = #{delyn}
)

mapper.update:
/* adm-master-owneradmincode-sql-oracle.xml - saveTOrderDtList */
UPDATE TADMIN_MST_OWCD_DT
   SET OWCDDTVALUE = #{owcddtvalue}
	 , CMT     = #{cmt}
 WHERE OWKEY 		= #{owkey}
   AND OWCDHDKEY 	= #{owcdhdkey}
   AND OWCDDTKEY   = #{owcddtkey}
   AND LAKEY		= #{lakey}
